<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>2048 Game</title>
    <style>
        * {
            box-sizing: border-box;
            margin: 0;
            padding: 0;
        }

        body {
            font-family: Arial, sans-serif;
            background-color: #bbada0;
            display: flex;
            flex-direction: column;
            align-items: center;
            justify-content: center;
            min-height: 100vh;
            color: white;
        }

        h1 {
            font-size: 60px;
            margin-bottom: 20px;
        }

        .header {
            display: flex;
            gap: 20px;
            align-items: center;
            margin-bottom: 30px;
        }

        #score-container {
            background-color: #bbada0;
            padding: 15px 25px;
            border-radius: 6px;
            text-align: center;
        }

        .score-label {
            font-size: 14px;
            color: #eee4da;
            text-transform: uppercase;
        }

        #score {
            font-size: 30px;
            font-weight: bold;
            color: white;
        }

        #reset {
            background-color: #8f7a66;
            color: white;
            border: none;
            padding: 15px 25px;
            font-size: 16px;
            border-radius: 6px;
            cursor: pointer;
            transition: background-color 0.2s;
        }

        #reset:hover {
            background-color: #7f6a56;
        }

        .game-container {
            position: relative;
            width: 480px;
            height: 480px;
            background-color: #bbada0;
            border-radius: 10px;
            padding: 15px;
            display: grid;
            grid-template-columns: repeat(4, 1fr);
            grid-template-rows: repeat(4, 1fr);
            gap: 15px;
        }

        .tile {
            width: 100%;
            height: 100%;
            background-color: #cdc1b4;
            border-radius: 6px;
            display: flex;
            align-items: center;
            justify-content: center;
            font-size: 55px;
            font-weight: bold;
            color: #776e65;
        }

        .tile-2 { background-color: #eee4da; }
        .tile-4 { background-color: #ede0c8; }
        .tile-8 { background-color: #f2b179; color: white; }
        .tile-16 { background-color: #f59563; color: white; }
        .tile-32 { background-color: #f67c5f; color: white; }
        .tile-64 { background-color: #f65e3b; color: white; }
        .tile-128 { background-color: #edcf72; color: white; font-size: 45px; }
        .tile-256 { background-color: #edcc61; color: white; font-size: 45px; }
        .tile-512 { background-color: #edc850; color: white; font-size: 45px; }
        .tile-1024 { background-color: #edc53f; color: white; font-size: 35px; }
        .tile-2048 { background-color: #edc22e; color: white; font-size: 35px; }

        @media (max-width: 500px) {
            .game-container {
                width: 360px;
                height: 360px;
                gap: 10px;
                padding: 10px;
            }

            .tile {
                font-size: 40px;
            }

            h1 { font-size: 45px; }
        }
    </style>
</head>
<body>
    <h1>2048</h1>

    <div class="header">
        <div id="score-container">
            <div class="score-label">Score</div>
            <div id="score">0</div>
        </div>

        <button id="reset">New Game</button>
    </div>

    <div class="game-container" id="board"></div>

    <script>
        // Game state
        let board = [];
        let score = 0;
        const size = 4;

        // Initialize game
        function initGame() {
            board = Array(size).fill().map(() => Array(size).fill(0));
            score = 0;

            // Add two initial tiles
            addRandomTile();
            addRandomTile();

            updateDisplay();
        }

        // Add a random tile (2 or 4) to an empty cell
        function addRandomTile() {
            const emptyCells = [];
            for (let r = 0; r < size; r++) {
                for (let c = 0; c < size; c++) {
                    if (board[r][c] === 0) {
                        emptyCells.push({r, c});
                    }
                }
            }

            if (emptyCells.length > 0) {
                const randomCell = emptyCells[Math.floor(Math.random() * emptyCells.length)];
                board[randomCell.r][randomCell.c] = Math.random() < 0.9 ? 2 : 4;
            }
        }

        // Update the display
        function updateDisplay() {
            // Update score
            document.getElementById('score').textContent = score;

            // Update board tiles
            const boardElement = document.getElementById('board');
            boardElement.innerHTML = '';

            for (let r = 0; r < size; r++) {
                for (let c = 0; c < size; c++) {
                    const tileValue = board[r][c];
                    const tileDiv = document.createElement('div');
                    tileDiv.className = `tile ${tileValue > 0 ? 'tile-' + tileValue : ''}`;
                    tileDiv.textContent = tileValue === 0 ? '' : tileValue;
                    boardElement.appendChild(tileDiv);
                }
            }
        }

        // Slide and merge a single row
        function slideRow(row) {
            // Remove zeros
            let filteredRow = row.filter(val => val !== 0);

            // Merge adjacent equal values
            for (let i = 0; i < filteredRow.length - 1; i++) {
                if (filteredRow[i] === filteredRow[i + 1]) {
                    filteredRow[i] *= 2;
                    score += filteredRow[i];
                    filteredRow[i + 1] = 0;
                    i++; // Skip next since it's merged
                }
            }

            // Remove zeros again after merging
            filteredRow = filteredRow.filter(val => val !== 0);

            // Pad with zeros to maintain size
            while (filteredRow.length < size) {
                filteredRow.push(0);
            }

            return filteredRow;
        }

        // Move in a direction
        function move(direction) {
            const oldBoard = JSON.stringify(board);
            let moved = false;

            if (direction === 'left') {
                for (let r = 0; r < size; r++) {
                    board[r] = slideRow(board[r]);
                }
            } else if (direction === 'right') {
                for (let r = 0; r < size; r++) {
                    // Reverse, slide, then reverse back
                    let reversedRow = [...board[r]].reverse();
                    board[r] = slideRow(reversedRow).reverse();
                }
            } else if (direction === 'up') {
                for (let c = 0; c < size; c++) {
                    // Extract column
                    const col = [];
                    for (let r = 0; r < size; r++) {
                        col.push(board[r][c]);
                    }

                    // Slide
                    const slidCol = slideRow(col);

                    // Put back
                    for (let r = 0; r < size; r++) {
                        if (board[r][c] !== slidCol[r]) moved = true;
                        board[r][c] = slidCol[r];
                    }
                }
            } else if (direction === 'down') {
                for (let c = 0; c < size; c++) {
                    // Extract column
                    const col = [];
                    for (let r = 0; r < size; r++) {
                        col.push(board[r][c]);
                    }

                    // Reverse, slide, reverse back
                    const reversedCol = [...col].reverse();
                    const slidCol = slideRow(reversedCol).reverse();

                    // Put back
                    for (let r = 0; r < size; r++) {
                        if (board[r][c] !== slidCol[r]) moved = true;
                        board[r][c] = slidCol[r];
                    }
                }
            }

            // Check if anything changed
            const newBoard = JSON.stringify(board);
            if (oldBoard !== newBoard) {
                addRandomTile();
                updateDisplay();
                return true;
            }

            return false;
        }

        // Expose game API on window
        window.game = {
            size,
            reset: initGame,
            move: (direction) => move(direction),
            board: () => JSON.parse(JSON.stringify(board)),
            setBoard: (arr) => {
                board = arr.map(row => [...row]);
                score = 0;
                updateDisplay();
            },
            score: () => score
        };

        // Event listeners
        document.addEventListener('keydown', (e) => {
            if (['ArrowLeft', 'ArrowRight', 'ArrowUp', 'ArrowDown'].includes(e.key)) {
                e.preventDefault();

                let direction = '';
                switch (e.key) {
                    case 'ArrowLeft': direction = 'left'; break;
                    case 'ArrowRight': direction = 'right'; break;
                    case 'ArrowUp': direction = 'up'; break;
                    case 'ArrowDown': direction = 'down'; break;
                }

                if (direction) {
                    move(direction);
                }
            }
        });

        document.getElementById('reset').addEventListener('click', initGame);

        // Initialize on load
        initGame();
    </script>
</body>
</html>
